class Solution:
    def createBinaryTree(self, descriptions):
        nodes = {}

        def get(v):
            if v not in nodes:
                nodes[v] = TreeNode(v)
            return nodes[v]

        children = set()
        parents = set()
        for p, c, is_left in descriptions:
            parent = get(p)
            child = get(c)
            if is_left == 1:
                parent.left = child
            else:
                parent.right = child
            children.add(c)
            parents.add(p)
        root_val = next(iter(parents - children))
        return nodes[root_val]

