class Solution:
    def createBinaryTree(self, descriptions):
        nodes = {}
        has_parent = set()
        for p, c, is_left in descriptions:
            if p not in nodes:
                nodes[p] = TreeNode(p)
            if c not in nodes:
                nodes[c] = TreeNode(c)
            if is_left == 1:
                nodes[p].left = nodes[c]
            else:
                nodes[p].right = nodes[c]
            has_parent.add(c)
        for p, _c, _is_left in descriptions:
            if p not in has_parent:
                return nodes[p]
        return None

