var createBinaryTree = function(descriptions) {
    const nodes = new Map();
    const hasParent = new Set();
    const get = (v) => {
        if (!nodes.has(v)) nodes.set(v, new TreeNode(v));
        return nodes.get(v);
    };
    for (const [p, c, isLeft] of descriptions) {
        const parent = get(p);
        const child = get(c);
        if (isLeft === 1) parent.left = child; else parent.right = child;
        hasParent.add(c);
    }
    for (const [p] of descriptions) {
        if (!hasParent.has(p)) return nodes.get(p);
    }
    return null;
};
